def _upsert_annotation(image_id: str, annotator_id: str, label: str, extra: Optional[Dict[str, Any]] = None):
    if not _image_exists(image_id):
        raise HTTPException(status_code=404, detail="image_id not found")
    _ensure_label_exists(label)
    annotation_id = str(uuid.uuid4())
    created_at = _now_iso()
    extra_json = json.dumps(extra or {}, separators=(",", ":"))
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            INSERT INTO annotations(id, image_id, annotator_id, label, created_at, extra_json)
            VALUES(?,?,?,?,?,?)
            ON CONFLICT(image_id, annotator_id) DO UPDATE SET
                label=excluded.label,
                created_at=excluded.created_at,
                extra_json=excluded.extra_json
            """,
            (annotation_id, image_id, annotator_id, label, created_at, extra_json),
        )
        conn.commit()
        conn.close()


def _aggregate_majority(image_id: str) -> Dict[str, Any]:
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            SELECT label, COUNT(*) as c
            FROM annotations
            WHERE image_id=?
            GROUP BY label
            ORDER BY c DESC, label ASC
            """,
            (image_id,),
        )
        rows = cur.fetchall()
        cur.execute("SELECT COUNT(*) as n FROM annotations WHERE image_id=?", (image_id,))
        n = cur.fetchone()["n"]
        conn.close()

    if n == 0:
        return {"image_id": image_id, "num_annotations": 0, "aggregated_label": None, "distribution": {}}

    dist = {r["label"]: int(r["c"]) for r in rows}
    top_label = rows[0]["label"]
    top_count = int(rows[0]["c"])
    tied = [r["label"] for r in rows if int(r["c"]) == top_count]
    aggregated = sorted(tied)[0]
    return {
        "image_id": image_id,
        "num_annotations": int(n),
        "aggregated_label": aggregated,
        "distribution": dist,
        "tie": len(tied) > 1,
        "tie_labels": sorted(tied),
    }


def _get_aggregated_dataset(min_votes: int = 1) -> List[Dict[str, Any]]:
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute("SELECT id, path FROM images")
        images = cur.fetchall()

        out = []
        for img in images:
            image_id = img["id"]
            cur.execute(
                """
                SELECT label, COUNT(*) as c
                FROM annotations
                WHERE image_id=?
                GROUP BY label
                ORDER BY c DESC, label ASC
                """,
                (image_id,),
            )
            rows = cur.fetchall()
            cur.execute("SELECT COUNT(*) as n FROM annotations WHERE image_id=?", (image_id,))
            n = int(cur.fetchone()["n"])
            if n < min_votes or n == 0:
                continue
            top_count = int(rows[0]["c"])
            tied = [r["label"] for r in rows if int(r["c"]) == top_count]
            agg = sorted(tied)[0]
            out.append({"image_id": image_id, "path": img["path"], "label": agg, "num_annotations": n})
        conn.close()
    return out


