@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    run_id = str(uuid.uuid4())
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            INSERT INTO training_runs(id, created_at, status, device, epochs, batch_size, lr, num_images, num_classes, class_to_idx_json, model_path, logs_json, error)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)
            """,
            (
                run_id,
                _now_iso(),
                "queued",
                None,
                int(req.epochs or TRAIN_EPOCHS),
                int(req.batch_size or TRAIN_BATCH_SIZE),
                float(req.lr or TRAIN_LR),
                None,
                None,
                None,
                None,
                json.dumps({"queued_at": _now_iso()}, separators=(",", ":")),
                None,
            ),
        )
        conn.commit()
        conn.close()

    def _runner():
        if not _train_lock.acquire(blocking=False):
            with _db_lock:
                conn = _get_conn()
                cur = conn.cursor()
                cur.execute("UPDATE training_runs SET status=?, error=? WHERE id=?", ("failed", "Training already in progress", run_id))
                conn.commit()
                conn.close()
            return
        try:
            _train_model_run(run_id, req)
        finally:
            _train_lock.release()

    t = threading.Thread(target=_runner, daemon=True)
    t.start()
    return TrainResponse(run_id=run_id, status="queued")


@app.get("/train/{run_id}")
def get_train_status(run_id: str):
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute("SELECT * FROM training_runs WHERE id=?", (run_id,))
        row = cur.fetchone()
        conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="run_id not found")
    return {
        "id": row["id"],
        "created_at": row["created_at"],
        "status": row["status"],
        "device": row["device"],
        "epochs": row["epochs"],
        "batch_size": row["batch_size"],
        "lr": row["lr"],
        "num_images": row["num_images"],
        "num_classes": row["num_classes"],
        "class_to_idx": json.loads(row["class_to_idx_json"] or "{}"),
        "model_path": row["model_path"],
        "logs": json.loads(row["logs_json"] or "{}"),
        "error": row["error"],
    }


@app.get("/models/{run_id}/artifact")
def download_model(run_id: str):
    with _db_lock:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute("SELECT model_path, status FROM training_runs WHERE id=?", (run_id,))
        row = cur.fetchone()
        conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="run_id not found")
    if row["status"] != "succeeded":
        raise HTTPException(status_code=409, detail="Model not available (run not succeeded)")
    path = row["model_path"]
    if not path or not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Artifact missing")
    return FileResponse(path, filename=os.path.basename(path))


